import { useNavigate } from 'react-router-dom';
import styled from 'styled-components';
import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';
import Container from '@mui/material/Container';
import Grid from '@mui/material/Grid';

import movie from '../Assets/movie.png'
import workout from '../Assets/workout.png'
import commandLine from '../Assets/commandLine.png'

const BoxWithHover = styled(Box)`
  transition: .5s;
  &:hover {
    transform: scale(1.05); /* Enlarge the image on hover */
  }
`;

const projectItem = (image, name, func) => {
  return (
    <Container
    sx={{display:'flex', flexDirection: 'column',
    alignItems: 'center'
    }}
    >
        <Box 
          component='img'
          src={image}
          alt='logo'
        />
          <Typography>{name}</Typography>
    </Container>
  );
};

function Projects () {
    const navigate = useNavigate();
    const reroute = (path) => {
        return () => navigate(path);
        // return () => window.open(path, '_blank');
    };

    return (
        <Container
        id='Projects'
        maxWidth='none'
        sx={{
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'space-evenly',
          mt: {xs: '15vh', sm: '25vh'}, 
          mb: '5vh',
          width: '75%',
        }}
        >
          <Typography 
            id='skills'
            variant='h2'
            my={4} 
          >
            Projects
          </Typography>

            {/* <Grid container direction='row' > */}
            <Grid item sx={{display: 'flex', flexDirection: 'row', alignItems: 'center'}}>
              <Grid item sx={{display: 'flex', flexDirection: 'column', alignItems: 'center'}}>
                <Box component='img' src={movie} sx={{height: '20vw', width: '20vw'}}/>
                <Typography> 'Topher Emby' </Typography>
              </Grid>
              <Grid item sx={{display: 'flex', flexDirection: 'column', alignItems: 'center'}}>
                <Box component='img' src={movie} sx={{height: '20vh', width: '20vh'}}/>
                <Typography> 'Topher Emby' </Typography>
              </Grid>
              <Grid item sx={{display: 'flex', flexDirection: 'column', alignItems: 'center'}}>
                <Box component='img' src={movie} sx={{height: '20vh', width: '20vh'}}/>
                <Typography> 'Topher Emby' </Typography>
              </Grid>
            </Grid>

        </Container>
    );
}

export default Projects;
